Please analyze the following requirements and output the task specification:

 A cognitive radio secondary user equipped with a single antenna collects $N = 256$ complex baseband samples per sensing interval and must decide whether a licensed band is occupied by a primary user under AWGN conditions (flat fading assumed compensated). The false-alarm probability must satisfy $P_{fa} \leq 0.01$, and reliable detection is expected at SNR as low as $-10$ dB. Design the detection algorithm, explain how the decision threshold is set, provide the theoretical $P_d$ vs. SNR curve from $-20$ dB to $0$ dB, and validate with Monte Carlo simulation. 

Reference Schema:
{
  "problem_understanding": {
    "task_category": "Primary category (one or more):\n  detection | estimation | recovery | beamforming | tracking | localization | others \nUse '|' to indicate multi-category problems.",
    "problem_statement": "In 2-4 sentences, describe:\n  (1) What is observed (input signal/measurement)?\n  (2) What needs to be estimated/detected/designed (output)?\n  (3) What is the core mathematical relationship between them?",
    "exploitable_structure": "Mathematical structure that an algorithm can exploit:\n  e.g., channel sparsity, low-rank covariance, Toeplitz/Hankel matrix structure, group sparsity, temporal correlation, manifold structure, shift-invariance.\n  Be specific: name the structure and how it constrains the problem.\n  Write 'none_identified' if genuinely unclear."
  },
  "system_model": {
    "waveform": "Signal/waveform type. Examples: single-carrier, OFDM, FMCW, SC-FDMA, OTFS.\nUse 'custom' for non-standard waveforms and describe in additional_params.",
    "antenna_config": {
      "num_tx": "Number of Tx antennas (int or null)",
      "num_rx": "Number of Rx antennas (int or null)",
      "array_type": "ULA / UPA / distributed / other (optional)",
      "additional_elements": "Dict for scenario-specific elements, e.g.:\n  {num_ris_elements: 64} or {num_virtual: 128}\n  Empty {} if not applicable."
    },
    "channel_model": {
      "model_name": "Channel/propagation model name. Examples: Rayleigh, Rician, 3GPP_CDL-C, free_space.\nUse 'custom' and describe in 'channel_properties' for non-standard models.",
      "channel_properties": "Key statistical/structural properties (list of tags):\n  e.g., [sparse, time_varying, frequency_selective, spatially_correlated, LoS_dominant, near_field]\n  This field is critical for algorithm design — fill even when model_name is standard."
    },
    "operating_conditions": {
      "carrier_freq_ghz": "Carrier frequency (GHz) or null",
      "bandwidth_mhz": "Bandwidth (MHz) or null",
      "mobility_kmh": "Mobility (km/h) or null"
    },
    "additional_params": "Dict of scenario-specific parameters not covered above.\n  Examples: {num_subcarriers: 1024, cp_length: 72, prf_hz: 1000, num_targets: 3}\n  Keep only parameters that directly affect algorithm design."
  },
  "performance_targets": {
    "primary_metric": "Primary performance metric with unit.\n  Examples: NMSE_dB, BER, RMSE_deg, sum_rate_bps_Hz, P_d_at_P_fa_1e-3.\n  Choose the single most important metric.",
    "secondary_metrics": "List of secondary metrics in priority order.\n  e.g., [complexity_flops, convergence_iterations, latency_ms]\n  Empty [] if only primary metric matters.",
    "theoretical_bound": "Known theoretical lower/upper bound, if applicable:\n  e.g., 'CRB for DoA estimation', 'channel capacity', 'matched filter bound'.\n  Write 'unknown' if not applicable or not known.",
    "baseline_algorithms": "Methods to compare against (user-specified or auto-selected).\n  If user specifies: list them directly.\n  If not specified: write 'auto' and the downstream planner will select appropriate baselines.\n  Examples: [LS, MMSE, OMP] or [ZF, MMSE_SIC] or 'auto'.",
    "target_value": "Quantitative target, if any. Format: {metric: value, at_snr_db: X}\n  e.g., {NMSE_dB: -20, at_snr_db: 10}, {Pd: 0.9, at_p_fa: 1e-3}\n  Null if no specific target; relative goals go in problem_understanding.problem_statement."
  },
  "constraints": {
    "complexity": "Computational constraint in natural language.\n  e.g., 'O(N log N) per iteration', 'parameters < 500k', 'no matrix inversion larger than 64x64'.\n  Null if unconstrained.",
    "data_availability": "Training data assumption:\n  'synthetic_only' — only simulated data available\n  'offline_dataset' — labeled dataset exists\n  'few_shot_online' — small amount of online adaptation data\n  'no_training_data' — purely model-based, no data-driven component\n  'not_applicable' — problem does not involve learning"
  },
  "design_preferences": {
    "approach": "User's preferred approach direction (SOFT hint, not mandate):\n  'auto' — let the system decide (RECOMMENDED default)\n  'classical_signal_processing' / 'optimization_based' / 'deep_learning' / 'deep_unfolding' / 'hybrid'\n  The planner SHOULD override this if analysis suggests a different approach is fundamentally more suitable.",
    "interpretability": "high / medium / low — preference, not constraint",
    "online_adaptation": "bool — whether online adaptation is desired"
  }
}

