        "monte_carlo": {
          "num_trials_per_snr": 100000,
          "noise_model": "complex Gaussian",
          "signal_model_under_H1": "complex Gaussian primary signal with power set by SNR",
          "estimated_outputs": ["empirical_P_fa", "empirical_P_d", "theoretical_P_d_overlay"]
        }
      }
    },
    "performance_targets": {
      "primary_metric": "P_d_at_P_fa_0.01",
      "secondary_metrics": [
        "P_fa_constraint_satisfaction",
        "ROC_AUC",
        "complexity_ops_per_interval"
      ],
      "theoretical_bound": "Neyman-Pearson optimality for fixed P_fa with unknown signal structure in AWGN (energy detector).",
      "baseline_algorithms": "auto",
      "target_value": {
        "P_fa_max": 0.01,
        "min_snr_db_for_evaluation": -10
      }
    },
    "constraints": {
      "complexity": "O(N) operations per sensing interval; no matrix inversion; suitable for real-time single-user spectrum sensing.",
      "data_availability": "no_training_data"
    },
    "design_preferences": {
      "approach": "classical_signal_processing",
      "interpretability": "high",
      "online_adaptation": false
    },
    "assumptions_made": [
      "Primary-user transmit signal structure is not exploited; non-coherent energy detection is selected as the robust default.",
      "Noise variance sigma_w2 is known or accurately estimated from calibration/quiet periods for threshold computation.",
      "Samples are i.i.d. within each sensing interval (no colored noise, no interference uncertainty).",
      "Single transmit stream for the primary user is assumed for system-model completeness; detector design is agnostic to modulation details.",
      "SNR sweep uses 2 dB steps from -20 dB to 0 dB for theoretical and Monte Carlo curve generation.",
      "Reliability at -10 dB is interpreted as an evaluation requirement (not a guaranteed numeric P_d target unless separately specified)."
    ]
  }
}

